module div_8bit (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output reg [15:0] result
);

    reg [16:0] sr;
    reg [7:0] divisor_reg;
    reg [7:0] neg_divisor;
    reg [3:0] cnt;
    reg [3:0] start_cnt;
    reg [7:0] remainder;
    reg [7:0] quotient;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            sr <= 0;
            divisor_reg <= 0;
            neg_divisor <= 0;
            cnt <= 0;
            start_cnt <= 0;
            remainder <= 0;
            quotient <= 0;
            res_valid <= 0;
            result <= 0;
        end else begin
            if (opn_valid && !res_valid) begin
                if (divisor == 0) begin

                end else begin
                    divisor_reg <= divisor;
                    neg_divisor <= -divisor;
                    remainder <= 0;
                    quotient <= 0;
                    start_cnt <= 8;
                end
            end

            if (start_cnt > 0) begin
                start_cnt <= start_cnt - 1;
            end else begin
                if (sign && (dividend[7] ^ divisor[7])) begin
                    remainder <= dividend[15:8] - divisor_reg;
                    quotient <= dividend[7:0];
                end else begin
                    remainder <= dividend[15:8] + divisor_reg;
                    quotient <= dividend[7:0];
                end

                if (remainder[7] == 0) begin
                    sr <= {remainder[6:0], dividend[7:0]};
                    cnt <= 8;
                end else begin
                    sr <= {remainder[6:0], dividend[7:0]};
                    cnt <= 8;
                end
            end

            if (cnt == 8) begin
                if (res_ready) begin
                    result <= {remainder, quotient};
                    res_valid <= 1;
                end
            end else if (res_valid && res_ready) begin
                res_valid <= 0;
            end
        end
    end

endmodule
